output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT(COUNT(DISTINCT ?game) AS ?count) WHERE {
  VALUES ?series {
    wd:Q1004352 wd:Q1004228 wd:Q3511262 wd:Q3511261
  }
  ?series wdt:P527 ?game .
  ?game wdt:P1475 ?homeTeam .
  ?game wdt:P1476 ?awayTeam .
  FILTER((?homeTeam = wd:Q334634 && ?awayTeam = wd:Q650840) ||(?homeTeam = wd:Q650840 && ?awayTeam = wd:Q334634))
  ?game wdt:P3705 ?attendance .
  FILTER(?attendance > 50000)
}

